(function(w){"use strict";const ID="split-bill";function compute(x){const total=Number(x.total),people=Number(x.people),round=Number(x.round||1);if(!Number.isFinite(total)||total<0)return{error:"총금액을 올바르게 입력해 주세요."};if(!Number.isInteger(people)||people<1)return{error:"인원수는 1명 이상 정수로 입력해 주세요."};const each=total/people;const rounded=Math.ceil(each/round)*round;return{each,rounded,totalRounded:rounded*people}}function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-grid-2"><div class="hm-calc-field"><label>총금액</label><input class="hm-calc-input" inputmode="numeric" placeholder="예: 78500"></div><div class="hm-calc-field"><label>인원수</label><input class="hm-calc-input" inputmode="numeric" placeholder="예: 4"></div></div><div class="hm-calc-field"><label>올림 단위</label><select class="hm-calc-select"><option value="1">1원</option><option value="10">10원</option><option value="100" selected>100원</option><option value="1000">1,000원</option></select></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const [total,people]=root.querySelectorAll("input"),round=root.querySelector("select"),go=root.querySelector("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const r=compute({total:api.parseNumber(total.value),people:api.parseNumber(people.value),round:api.parseNumber(round.value)});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");api.setResult(res,api.resultCard("1인당 금액",api.formatWon(r.rounded),`<dl><dt>정확한 1인당 금액</dt><dd>${api.formatWon(r.each)}</dd><dt>올림 후 총합</dt><dd>${api.formatWon(r.totalRounded)}</dd></dl>`));});}w.HM_CALC.register(ID,{compute,render});})(window);
